import 'package:flutter/material.dart';
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';
import 'package:task_manager_flutter/data/utils/api_links.dart';
import 'package:task_manager_flutter/ui/widgets/generic_grid_screen.dart';
import 'audit_model.dart';
import 'empresa_model.dart';
import 'file_attachment_model.dart';
import 'forma_pagamento_model.dart';
import 'parceiro_model.dart';

class ObrigacaoFiscal {
  int? id;
  String codigo;
  String descricao;
  int diaVencimento;
  int? regimeTributarioId;

  ObrigacaoFiscal({
    this.id,
    required this.codigo,
    required this.descricao,
    required this.diaVencimento,
    this.regimeTributarioId,
  });

  factory ObrigacaoFiscal.fromJson(Map<String, dynamic> json) {
    return ObrigacaoFiscal(
      id: json['id'],
      codigo: json['codigo'],
      descricao: json['descricao'],
      diaVencimento: json['diaVencimento'],
      regimeTributarioId: json['regimeTributarioId'],
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'codigo': codigo,
      'descricao': descricao,
      'diaVencimento': diaVencimento,
      'regimeTributarioId': regimeTributarioId,
    };
  }
}
  // Classes auxiliares para as entidades relacionadas
  static Future<List<Map<String, dynamic>>> loadFormasPagamento() async {
    final NetworkResponse response = await NetworkCaller().getRequest(
      ApiLinks.allFormasPagamento,
    );

    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      return data
          .map(
            (item) => {'value': item['id'], 'label': item['nome'].toString()},
          )
          .toList();
    }
    return [];
  }

  static Future<List<Map<String, dynamic>>> loadParceiros() async {
    final NetworkResponse response = await NetworkCaller().getRequest(
      ApiLinks.allParceiros,
    );

    if (response.isSuccess && response.body != null) {
      final List<dynamic> data = response.body!['data']['dados'] ?? [];
      return data
          .map(
            (item) => {'value': item['id'], 'label': item['nome'].toString()},
          )
          .toList();
    }
    return [];
  }

  static List<FieldConfig> fieldConfigs = [
    FieldConfig(
      label: "Fornecedor",
      fieldName: "parceiro.id",
      displayFieldName: "parceiro.nome",
      icon: Icons.business,
      isInForm: true,
      isFilterable: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async => await loadParceiros(),
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
      isRequired: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Fornecedor Dev",
      fieldName: "parceiroDev.id",
      displayFieldName: "parceiroDev.nome",
      icon: Icons.business,
      isInForm: true,
      isFilterable: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async => await loadParceiros(),
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
      isRequired: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Descrição",
      fieldName: "descricao",
      icon: Icons.description,
      isInForm: true,
      isFilterable: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Valor",
      fieldName: "valor",
      icon: Icons.attach_money,
      isInForm: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Data Vencimento",
      fieldName: "dataVencimento",
      icon: Icons.calendar_today,
      isInForm: true,
      isFilterable: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Status",
      fieldName: "status",
      icon: Icons.info,
      isFilterable: true,
      isVisibleByDefault: true,
      isFixed: false,
      isInForm: false,
    ),
    FieldConfig(
      label: "Data Baixa",
      fieldName: "dataBaixa",
      icon: Icons.calendar_today,
      isVisibleByDefault: false,
      isFixed: false,
      isInForm: false,
    ),
    FieldConfig(
      label: "Valor Baixa",
      fieldName: "valorBaixa",
      icon: Icons.attach_money,
      isVisibleByDefault: false,
      isFixed: false,
      isInForm: false,
    ),
    FieldConfig(
      label: "Valor Multa",
      fieldName: "valorMulta",
      icon: Icons.attach_money,
      isInForm: true,
      isVisibleByDefault: false,
      isFixed: false,
    ),
    FieldConfig(
      label: "Valor Juros",
      fieldName: "valorJuros",
      icon: Icons.attach_money,
      isInForm: true,
      isVisibleByDefault: false,
      isFixed: false,
    ),
    FieldConfig(
      label: "Valor Desconto",
      fieldName: "valorDesconto",
      icon: Icons.attach_money,
      isInForm: true,
      isVisibleByDefault: false,
      isFixed: false,
    ),
    FieldConfig(
      label: "Forma Pagamento",
      fieldName: "formaPagamento.id",
      displayFieldName: "formaPagamento.nome",
      icon: Icons.payment,
      isInForm: true,
      isFilterable: true,
      fieldType: FieldType.dropdown,
      dropdownFutureBuilder: () async => await loadFormasPagamento(),
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
      isRequired: true,
      isVisibleByDefault: true,
      isFixed: false,
    ),
    FieldConfig(
      label: "Status",
      fieldName: "status",
      icon: Icons.check_circle,
      isFilterable: true,
      isVisibleByDefault: true,
      isFixed: false,
      fieldType: FieldType.dropdown,
      dropdownOptions: [
        {'value': 0, 'label': 'Aberto'},
        {'value': 1, 'label': 'Baixada '},
        {'value': 2, 'label': 'Cancelado'},
      ],
      dropdownSelectedValue: 0, // Valor padrão selecionado
      enabled: false,
      dropdownValueField: 'value',
      dropdownDisplayField: 'label',
    ),
    FieldConfig(
      label: "Anexo",
      fieldName: "file.id",
      displayFieldName: "file.nome",
      fieldType: FieldType.file,
      enabled: true, // Pode ser false para desabilitar
    ),
  ];
}
